#include <fstream>
#include <iostream>
#include <vector>

int main() {
    const int n = 42;
    std::ifstream in("intercityDistance.txt");
    std::vector<std::vector<int>> d(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) in >> d[i][j];

    std::vector<bool> visited(n, false);
    std::vector<int> tour{0};
    visited[0] = true;
    int cur = 0;
    for (int step = 0; step < n - 1; ++step) {
        int best = -1, bestD = 0;
        for (int j = 0; j < n; ++j)
            if (!visited[j] && (best == -1 || d[cur][j] < bestD)) { best = j; bestD = d[cur][j]; }
        tour.push_back(best);
        visited[best] = true;
        cur = best;
    }
    std::cout << "TOUR";
    for (int c : tour) std::cout << ' ' << (c + 1);
    std::cout << '\n';
}

