package main

import (
	"fmt"
	"os"
)

func main() {
	const n = 42
	f, err := os.Open("intercityDistance.txt")
	if err != nil {
		panic(err)
	}
	defer f.Close()

	d := make([][]int, n)
	for i := 0; i < n; i++ {
		d[i] = make([]int, n)
		for j := 0; j < n; j++ {
			fmt.Fscan(f, &d[i][j])
		}
	}

	visited := make([]bool, n)
	tour := []int{0}
	visited[0] = true
	cur := 0
	for step := 0; step < n-1; step++ {
		best, bestD := -1, 0
		for j := 0; j < n; j++ {
			if !visited[j] && (best == -1 || d[cur][j] < bestD) {
				best, bestD = j, d[cur][j]
			}
		}
		tour = append(tour, best)
		visited[best] = true
		cur = best
	}

	fmt.Print("TOUR")
	for _, c := range tour {
		fmt.Printf(" %d", c+1)
	}
	fmt.Println()
}

