use std::fs;

fn main() {
    let n = 42;
    let text = fs::read_to_string("intercityDistance.txt").expect("read input");
    let nums: Vec<i64> = text.split_whitespace().map(|x| x.parse().unwrap()).collect();
    let d: Vec<&[i64]> = (0..n).map(|i| &nums[i * n..(i + 1) * n]).collect();

    let mut visited = vec![false; n];
    let mut tour = vec![0usize];
    visited[0] = true;
    let mut cur = 0usize;
    for _ in 0..n - 1 {
        let (mut best, mut best_d): (i64, i64) = (-1, 0);
        for j in 0..n {
            if !visited[j] && (best == -1 || d[cur][j] < best_d) { best = j as i64; best_d = d[cur][j]; }
        }
        let b = best as usize;
        tour.push(b);
        visited[b] = true;
        cur = b;
    }
    let s: Vec<String> = tour.iter().map(|c| (c + 1).to_string()).collect();
    println!("TOUR {}", s.join(" "));
}

