import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        int n = 42;
        String[] tok = Files.readString(Path.of("intercityDistance.txt")).trim().split("\\s+");
        int[][] d = new int[n][n];
        for (int i = 0; i < n; i++)
            for (int j = 0; j < n; j++) d[i][j] = Integer.parseInt(tok[i * n + j]);

        boolean[] visited = new boolean[n];
        List<Integer> tour = new ArrayList<>();
        visited[0] = true;
        tour.add(0);
        int cur = 0;
        for (int step = 0; step < n - 1; step++) {
            int best = -1, bestD = 0;
            for (int j = 0; j < n; j++)
                if (!visited[j] && (best == -1 || d[cur][j] < bestD)) { best = j; bestD = d[cur][j]; }
            tour.add(best);
            visited[best] = true;
            cur = best;
        }
        StringBuilder sb = new StringBuilder("TOUR");
        for (int c : tour) sb.append(' ').append(c + 1);
        System.out.println(sb);
    }
}
